def get_max_multiplication_from_lists(l1, l2):
    l1_mult = get_product(*l1)
    l2_mult = get_product(*l2)
    return max(l1_mult, l2_mult)

def get_product(*args):
    product = 1
    for arg in args:
        product *= arg
    return product

