def get_maximal_second_element_squared(numbers: List[List[int]]) -> int:
    validate_list_length(numbers)
    second_elements = get_second_elements(numbers)
    squared_elements = get_squared_elements(second_elements)
    return max(squared_elements)


def validate_list_length(numbers: List[int]) -> None:
    if len(numbers) < 2:
        raise ValueError("List must have at least two elements.")


def get_second_elements(numbers: List[int]) -> List[int]:
    return [numbers[i][1] for i in range(len(numbers))]


def get_squared_elements(numbers: List[int]) -> List[int]:
    return [number ** 2 for number in numbers]}}}

