def get_sum_of_absolute_differences(l1: List[int], l2: List[int]) -> int:
    differences = get_absolute_differences(l1, l2)
    return sum(differences)


def get_absolute_differences(l1: List[int], l2: List[int]) -> List[int]:
    return [abs(a - b) for a, b in zip(l1, l2)]

