import statistics


def get_average_of_second_elements(numbers: List[List[int]]) -> float:
    second_elements = get_second_elements(numbers)
    return statistics.mean(second_elements)


def get_second_elements(numbers: List[List[int]]) -> List[int]:
    return [sublist[1] for sublist in numbers]

